// GetHash returns the stored hash for a path.
func (ix *Indexer) GetHash(path string) (string, bool) {
	ix.mu.RLock()
	defer ix.mu.RUnlock()

	h, ok := ix.hashes[path]
	return h, ok
}

// RemoveHash removes the stored hash for a path.
func (ix *Indexer) RemoveHash(path string) {
	ix.mu.Lock()
	defer ix.mu.Unlock()

	delete(ix.hashes, path)
}
